(function(){'use strict';const CONFIG={brand:'LED Solutions',phone:'(555) 123-4567',email:'info@ledsolutions.net',area:'Southeast United States',green:'#A3D55D',dark:'#1A1A1A',gray:'#7A7A7A',light:'#F5F5F5',white:'#FFFFFF',};const IMAGES={hero:'https://images.unsplash.com/photo-1497366216548-37526070297c?w=1920&q=80',services:'https://images.unsplash.com/photo-1504384308090-c894fdcc538d?w=800&q=80',industrial:'https://images.unsplash.com/photo-1565793298595-6a879b1d9492?w=800&q=80',controls:'https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=800&q=80',beforeDim:'https://images.unsplash.com/photo-1497366811353-6870744d04b2?w=800&q=80',afterBright:'https://images.unsplash.com/photo-1497366216548-37526070297c?w=800&q=80',team:'https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=800&q=80',cre:'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=800&q=80',healthcare:'https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?w=800&q=80',education:'https://images.unsplash.com/photo-1562774053-701939374585?w=800&q=80',retail:'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=800&q=80',sports:'https://images.unsplash.com/photo-1577223625816-7546f13df25d?w=800&q=80',contact:'https://images.unsplash.com/photo-1423666639041-f56000c27a9a?w=800&q=80',};const CASE_STUDIES=[{id:'metro-center',title:'Metro Center Office Complex',type:'Commercial Office',sqft:'450,000',fixtures:'4,200',reduction:72,savings:'$340K',annualSavings:'$340,000',rebates:'$127K',rebatesFull:'$127,000',payback:'1.8',img:IMAGES.cre,desc:'A flagship 450,000 SF Class-A office complex sought to modernize aging fluorescent systems while minimizing tenant disruption. LED Solutions delivered a phased retrofit across 12 floors, replacing 4,200 fixtures with premium LED panels and integrated daylight harvesting controls.',results:['72% reduction in lighting energy consumption','$340,000 in verified annual savings','$127,000 in utility rebates captured','Zero tenant complaints during installation','Improved tenant satisfaction scores by 23%']},{id:'eastland-distribution',title:'Eastland Distribution Center',type:'Industrial Warehouse',sqft:'280,000',fixtures:'2,800',reduction:74,savings:'$195K',annualSavings:'$195,000',rebates:'$89K',rebatesFull:'$89,000',payback:'1.6',img:IMAGES.industrial,desc:'Eastland\'s 280,000 SF distribution center operated 18 hours daily under inefficient HID lighting with poor uniformity. LED Solutions engineered a complete high-bay LED retrofit with intelligent motion controls, transforming both energy performance and worker safety.',results:['74% reduction in lighting energy consumption','$195,000 in verified annual savings','$89,000 in utility rebates captured','Improved lumen uniformity by 40%','Instant-on eliminated 15-minute warm-up delays']},{id:'riverside-shopping',title:'Riverside Shopping Center',type:'Retail & Exterior',sqft:'185,000',fixtures:'1,900',reduction:60,savings:'$142K',annualSavings:'$142,000',rebates:'$67K',rebatesFull:'$67,000',payback:'2.1',img:IMAGES.retail,desc:'This 185,000 SF open-air shopping center needed to refresh interior tenant common areas and exterior parking lot lighting while improving safety and curb appeal. LED Solutions delivered a comprehensive solution covering both interior and exterior environments.',results:['60% reduction in lighting energy consumption','$142,000 in verified annual savings','$67,000 in utility rebates captured','Improved parking lot illumination by 65%','Enhanced tenant and customer experience']},{id:'bayshore-medical',title:'Bayshore Medical Campus',type:'Healthcare',sqft:'320,000',fixtures:'3,100',reduction:65,savings:'$285K',annualSavings:'$285,000',rebates:'$156K',rebatesFull:'$156,000',payback:'2.4',img:IMAGES.healthcare,desc:'Bayshore Medical Campus required code-compliant, flicker-free, tunable lighting across patient rooms, surgical suites, and administrative areas. LED Solutions delivered a healthcare-grade LED system meeting stringent clinical requirements.',results:['65% reduction in lighting energy consumption','$285,000 in verified annual savings','$156,000 in utility rebates captured','100% flicker-free for sensitive clinical areas','Tunable color temperature in patient rooms']},];const SERVICES=[{id:'retrofit',title:'Commercial LED Retrofit',short:'Cut energy costs 50\u201370%. Turnkey LED retrofits from audit to install \u2014 one partner, one outcome.',icon:'\u26A1',img:IMAGES.services,stat:'50\u201370%',statLabel:'Energy Savings'},{id:'controls',title:'Smart Controls & Integration',short:'20\u201340% additional savings beyond LED. Occupancy sensing, scheduling, BAS integration.',icon:'\uD83C\uDFAF',img:IMAGES.controls,stat:'20\u201340%',statLabel:'Additional Savings'},{id:'rebates',title:'Utility Rebate Management',short:'$2.1M+ captured. We identify, apply for, and secure every rebate dollar available.',icon:'\uD83D\uDCB0',img:IMAGES.cre,stat:'$2.1M+',statLabel:'Rebates Captured'},{id:'sports',title:'Sports & Athletic Lighting',short:'Broadcast-quality illumination at 50\u201370% less energy. Instant-on, zero warm-up.',icon:'\uD83C\uDFC6',img:IMAGES.sports,stat:'50\u201370%',statLabel:'Energy Savings'},{id:'exterior',title:'Exterior & Parking',short:'Improved safety and visibility. 55\u201370% savings. Reduced liability exposure.',icon:'\uD83C\uDF03',img:IMAGES.contact,stat:'55\u201370%',statLabel:'Energy Savings'},{id:'audit',title:'Free Energy Audit',short:'Engineering-grade assessment of your current lighting. Not a walkthrough with a sales pitch.',icon:'\uD83D\uDD0D',img:IMAGES.team,stat:'$0',statLabel:'Cost to You'},];const INDUSTRIES=[{title:'Commercial Real Estate',stat:'55\u201370%',desc:'Increased NOI through dramatic energy reduction. Attract premium tenants with modern, efficient buildings.',img:IMAGES.cre},{title:'Industrial & Manufacturing',stat:'60\u201375%',desc:'High-bay LED and controls for demanding 24/7 environments. Better visibility, fewer accidents.',img:IMAGES.industrial},{title:'Retail & Shopping Centers',stat:'50\u201365%',desc:'Enhanced customer experience with better color rendering and consistent illumination.',img:IMAGES.retail},{title:'Healthcare',stat:'Code-compliant',desc:'Flicker-free, tunable lighting for clinical, patient, and administrative environments.',img:IMAGES.healthcare},{title:'Education',stat:'Budget-friendly',desc:'Campus-wide LED solutions that reduce operating costs and improve learning environments.',img:IMAGES.education},];const TESTIMONIALS=[{quote:'LED Solutions delivered exactly what they promised \u2014 67% energy reduction and a clean install that didn\'t disrupt our tenants. The rebate capture alone justified the project.',name:'Sarah Chen',role:'VP Operations',company:'Metro Properties'},{quote:'We\'ve worked with lighting contractors before. LED Solutions is different \u2014 they brought engineering rigor and managed every detail. Our warehouse visibility improved dramatically.',name:'Marcus Webb',role:'Facilities Director',company:'Southeast Distribution Co.'},{quote:'The controls integration was what set them apart. We\'re seeing 40% additional savings beyond the LED retrofit itself. The data visibility alone was worth the investment.',name:'James Rodriguez',role:'Building Engineer',company:'Riverside REIT'},{quote:'From audit to final walkthrough, LED Solutions managed everything. The project paid for itself in 16 months. I wish we\'d done it sooner.',name:'Patricia Owens',role:'CFO',company:'Bayshore Healthcare'},];const PROCESS_STEPS=[{num:'01',title:'Free Energy Audit',desc:'Engineering-grade assessment of your current lighting systems, energy usage, and opportunities.'},{num:'02',title:'Custom Proposal',desc:'Detailed ROI analysis with projected savings, rebate estimates, and recommended solutions.'},{num:'03',title:'Rebate Capture',desc:'We handle all utility rebate paperwork, pre-approval, and secure maximum incentives.'},{num:'04',title:'Professional Install',desc:'Minimal disruption. Phased rollout. Certified electricians. Clean job sites.'},{num:'05',title:'Verify & Optimize',desc:'Post-install measurement & verification. We prove the savings are real.'},];let currentRoute='';let stickyDismissed=false;let testimonialIdx=0;let countersAnimated={};const $=(sel,ctx)=>(ctx||document).querySelector(sel);const $$=(sel,ctx)=>Array.from((ctx||document).querySelectorAll(sel));const el=(tag,attrs,...children)=>{const e=document.createElement(tag);if(attrs)Object.entries(attrs).forEach(([k,v])=>{if(k==='className')e.className=v;else if(k==='innerHTML')e.innerHTML=v;else if(k.startsWith('on'))e.addEventListener(k.slice(2).toLowerCase(),v);else e.setAttribute(k,v);});children.flat(Infinity).forEach(c=>{if(c==null)return;e.appendChild(typeof c==='string'?document.createTextNode(c):c);});return e;};function navigate(hash){window.location.hash=hash;}
function slugify(s){return s.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');}
function loadFont(){if(!$('link[href*="fonts.googleapis.com/css2?family=Inter"]')){const link=el('link',{rel:'stylesheet',href:'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap'});document.head.appendChild(link);}}
function injectCSS(){if($('#led-solutions-css'))return;const style=el('style',{id:'led-solutions-css'});style.textContent=`:root{--color-primary:#A3D55D;--color-primary-dark:#8BC34A;--color-dark:#1A1A1A;--color-gray:#7A7A7A;--color-light:#F5F5F5;--color-white:#FFFFFF;--font-main:'Inter',-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;--transition-smooth:cubic-bezier(0.16,1,0.3,1);--max-width:1200px;--section-padding:120px;--nav-height:72px;}*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
html{scroll-behavior:smooth;-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale;}
body{font-family:var(--font-main);color:var(--color-dark);background:var(--color-white);line-height:1.7;font-size:18px;overflow-x:hidden;}
img{max-width:100%;display:block;}
a{color:inherit;text-decoration:none;}
button{font-family:var(--font-main);cursor:pointer;border:none;}
input,select,textarea{font-family:var(--font-main);font-size:16px;}
#ls-scroll-progress{position:fixed;top:0;left:0;height:3px;z-index:10001;background:var(--color-primary);width:0%;transition:width 0.1s linear;}
#ls-nav{position:fixed;top:0;left:0;right:0;z-index:10000;height:var(--nav-height);display:flex;align-items:center;justify-content:center;transition:background 0.4s ease,box-shadow 0.4s ease,backdrop-filter 0.4s ease;background:transparent;}#ls-nav.scrolled{background:rgba(255,255,255,0.88);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);box-shadow:0 1px 0 rgba(0,0,0,0.06);}#ls-nav.dark-hero{}#ls-nav.scrolled.ls-nav-link,#ls-nav.scrolled.ls-nav-logo{color:var(--color-dark);}.ls-nav-inner{max-width:var(--max-width);width:100%;padding:0 32px;display:flex;align-items:center;justify-content:space-between;}.ls-nav-logo{font-size:20px;font-weight:800;letter-spacing:-0.02em;color:#fff;transition:color 0.3s ease;display:flex;align-items:center;gap:8px;cursor:pointer;}.ls-nav-logo span{color:var(--color-primary);}.ls-nav-links{display:flex;gap:32px;align-items:center;}.ls-nav-link{font-size:14px;font-weight:500;color:rgba(255,255,255,0.85);transition:color 0.3s ease;position:relative;letter-spacing:0.01em;cursor:pointer;}.ls-nav-link:hover{color:var(--color-primary);}.ls-nav-link.active::after{content:'';position:absolute;bottom:-4px;left:50%;transform:translateX(-50%);width:5px;height:5px;border-radius:50%;background:var(--color-primary);}.ls-nav-cta{background:var(--color-primary);color:var(--color-dark);font-weight:700;font-size:14px;padding:10px 24px;border-radius:8px;transition:transform 0.3s var(--transition-smooth),box-shadow 0.3s ease;cursor:pointer;}.ls-nav-cta:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(163,213,93,0.3);}
.ls-hamburger{display:none;flex-direction:column;gap:5px;cursor:pointer;background:none;border:none;padding:4px;}.ls-hamburger span{width:24px;height:2px;background:#fff;transition:all 0.3s ease;border-radius:2px;}#ls-nav.scrolled.ls-hamburger span{background:var(--color-dark);}.ls-mobile-menu{display:none;position:fixed;top:var(--nav-height);left:0;right:0;bottom:0;background:rgba(255,255,255,0.98);backdrop-filter:blur(20px);flex-direction:column;align-items:center;justify-content:center;gap:24px;z-index:9999;}.ls-mobile-menu.open{display:flex;}.ls-mobile-menu a{font-size:24px;font-weight:600;color:var(--color-dark);padding:12px 0;transition:color 0.3s ease;}.ls-mobile-menu a:hover{color:var(--color-primary);}@media(max-width:900px){.ls-nav-links{display:none;}.ls-hamburger{display:flex;}}
#ls-app{opacity:1;transition:opacity 0.3s ease;}#ls-app.transitioning{opacity:0;}
.ls-hero{position:relative;min-height:100vh;display:flex;align-items:center;justify-content:center;overflow:hidden;}.ls-hero-bg{position:absolute;inset:0;background-size:cover;background-position:center;z-index:0;}.ls-hero-bg::after{content:'';position:absolute;inset:0;background:linear-gradient(180deg,rgba(0,0,0,0.55)0%,rgba(0,0,0,0.7)100%);}.ls-hero-content{position:relative;z-index:2;text-align:center;color:#fff;max-width:900px;padding:0 32px;}.ls-hero-sub{font-size:14px;font-weight:600;letter-spacing:0.15em;text-transform:uppercase;color:var(--color-primary);margin-bottom:24px;}.ls-hero h1{font-size:clamp(40px,8vw,84px);font-weight:800;line-height:1.05;letter-spacing:-0.03em;margin-bottom:24px;}.ls-hero p{font-size:clamp(16px,2vw,20px);color:rgba(255,255,255,0.75);max-width:600px;margin:0 auto 40px;line-height:1.6;}.ls-hero-actions{display:flex;gap:16px;justify-content:center;flex-wrap:wrap;}.ls-hero.ls-btn-primary{background:var(--color-primary);color:var(--color-dark);font-weight:700;font-size:16px;padding:16px 36px;border-radius:12px;display:inline-flex;align-items:center;gap:8px;transition:transform 0.3s var(--transition-smooth),box-shadow 0.3s ease;animation:cta-glow 3s ease-in-out infinite;}.ls-hero.ls-btn-primary:hover{transform:translateY(-3px);box-shadow:0 12px 32px rgba(163,213,93,0.35);}.ls-hero.ls-btn-outline{border:2px solid rgba(255,255,255,0.4);color:#fff;font-weight:600;font-size:16px;padding:14px 36px;border-radius:12px;background:transparent;transition:all 0.3s ease;display:inline-flex;align-items:center;gap:8px;}.ls-hero.ls-btn-outline:hover{border-color:#fff;background:rgba(255,255,255,0.08);}@keyframes cta-glow{0%,100%{box-shadow:0 4px 16px rgba(163,213,93,0.2);}
50%{box-shadow:0 4px 32px rgba(163,213,93,0.45);}}
.ls-page-hero{position:relative;min-height:50vh;display:flex;align-items:center;justify-content:center;overflow:hidden;}.ls-page-hero.ls-hero-bg::after{background:linear-gradient(180deg,rgba(0,0,0,0.6)0%,rgba(0,0,0,0.75)100%);}.ls-page-hero.ls-hero-content{padding-top:var(--nav-height);}
.ls-scroll-hint{position:absolute;bottom:40px;left:50%;transform:translateX(-50%);z-index:2;animation:bounce-down 2s ease infinite;}.ls-scroll-hint svg{width:28px;height:28px;stroke:rgba(255,255,255,0.5);stroke-width:2;fill:none;}@keyframes bounce-down{0%,100%{transform:translateX(-50%)translateY(0);}50%{transform:translateX(-50%)translateY(10px);}}
.ls-section{padding:var(--section-padding)0;}.ls-section.dark{background:var(--color-dark);color:#fff;}.ls-section.light{background:var(--color-light);}.ls-section.green{background:var(--color-primary);}.ls-container{max-width:var(--max-width);margin:0 auto;padding:0 32px;}.ls-section-label{font-size:13px;font-weight:700;letter-spacing:0.15em;text-transform:uppercase;color:var(--color-primary);margin-bottom:16px;}.ls-section.dark.ls-section-label{color:var(--color-primary);}.ls-section-title{font-size:clamp(32px,5vw,56px);font-weight:800;letter-spacing:-0.03em;line-height:1.1;margin-bottom:20px;}.ls-section-subtitle{font-size:18px;color:var(--color-gray);max-width:600px;line-height:1.6;}.ls-section.dark.ls-section-subtitle{color:rgba(255,255,255,0.6);}
.ls-reveal{opacity:0;transform:translateY(40px);transition:opacity 0.8s var(--transition-smooth),transform 0.8s var(--transition-smooth);}.ls-reveal.visible{opacity:1;transform:translateY(0);}.ls-reveal-left{opacity:0;transform:translateX(-40px);transition:opacity 0.8s var(--transition-smooth),transform 0.8s var(--transition-smooth);}.ls-reveal-left.visible{opacity:1;transform:translateX(0);}.ls-reveal-right{opacity:0;transform:translateX(40px);transition:opacity 0.8s var(--transition-smooth),transform 0.8s var(--transition-smooth);}.ls-reveal-right.visible{opacity:1;transform:translateX(0);}
.ls-btn{display:inline-flex;align-items:center;gap:8px;font-weight:700;font-size:16px;padding:14px 32px;border-radius:10px;transition:all 0.3s var(--transition-smooth);cursor:pointer;border:none;}.ls-btn-primary-std{background:var(--color-primary);color:var(--color-dark);}.ls-btn-primary-std:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(163,213,93,0.3);}.ls-btn-dark{background:var(--color-dark);color:#fff;}.ls-btn-dark:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,0,0,0.15);}.ls-btn-white{background:#fff;color:var(--color-dark);}.ls-btn-white:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,0,0,0.1);}.ls-btn-outline-dark{background:transparent;border:2px solid var(--color-dark);color:var(--color-dark);}.ls-btn-outline-dark:hover{background:var(--color-dark);color:#fff;}.ls-text-link{font-weight:600;font-size:16px;display:inline-flex;align-items:center;gap:6px;position:relative;color:var(--color-dark);cursor:pointer;transition:gap 0.3s ease;}.ls-text-link::after{content:'';position:absolute;bottom:-2px;left:0;width:0;height:2px;background:var(--color-primary);transition:width 0.3s ease;}.ls-text-link:hover::after{width:100%;}.ls-text-link:hover{gap:10px;}.ls-section.dark.ls-text-link{color:#fff;}
.ls-card{background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.06);transition:transform 0.4s var(--transition-smooth),box-shadow 0.4s var(--transition-smooth);}.ls-card:hover{transform:translateY(-8px);box-shadow:0 16px 48px rgba(0,0,0,0.1);}.ls-card-img{width:100%;height:220px;object-fit:cover;transition:transform 0.6s var(--transition-smooth);}.ls-card:hover.ls-card-img{transform:scale(1.04);}.ls-card-img-wrap{overflow:hidden;}.ls-card-body{padding:28px;}.ls-card-title{font-size:20px;font-weight:700;margin-bottom:8px;letter-spacing:-0.01em;}.ls-card-text{font-size:15px;color:var(--color-gray);line-height:1.6;margin-bottom:16px;}.ls-card-stat{font-size:28px;font-weight:800;color:var(--color-primary);}.ls-card-stat-label{font-size:13px;color:var(--color-gray);font-weight:500;}
.ls-grid-2{display:grid;grid-template-columns:repeat(2,1fr);gap:32px;}.ls-grid-3{display:grid;grid-template-columns:repeat(3,1fr);gap:32px;}.ls-grid-4{display:grid;grid-template-columns:repeat(4,1fr);gap:32px;}.ls-grid-60-40{display:grid;grid-template-columns:1.5fr 1fr;gap:64px;align-items:center;}.ls-grid-40-60{display:grid;grid-template-columns:1fr 1.5fr;gap:64px;align-items:center;}@media(max-width:900px){.ls-grid-2,.ls-grid-3,.ls-grid-4,.ls-grid-60-40,.ls-grid-40-60{grid-template-columns:1fr;}.ls-section{padding:80px 0;}:root{--section-padding:80px;}}@media(max-width:600px){.ls-section{padding:60px 0;}.ls-container{padding:0 20px;}}
.ls-stats-row{display:grid;grid-template-columns:repeat(4,1fr);gap:40px;text-align:center;}.ls-stat-num{font-size:clamp(36px,5vw,56px);font-weight:800;letter-spacing:-0.03em;color:var(--color-dark);line-height:1;}.ls-section.dark.ls-stat-num{color:var(--color-primary);}.ls-stat-label{font-size:14px;font-weight:500;color:var(--color-gray);margin-top:8px;text-transform:uppercase;letter-spacing:0.08em;}.ls-section.dark.ls-stat-label{color:rgba(255,255,255,0.5);}@media(max-width:700px){.ls-stats-row{grid-template-columns:repeat(2,1fr);gap:32px;}}
.ls-marquee-wrap{overflow:hidden;padding:40px 0;border-bottom:1px solid rgba(0,0,0,0.06);}.ls-marquee{display:flex;gap:60px;animation:marquee 30s linear infinite;width:max-content;}.ls-marquee-item{width:120px;height:40px;border-radius:8px;background:var(--color-light);opacity:0.4;flex-shrink:0;}@keyframes marquee{0%{transform:translateX(0);}100%{transform:translateX(-50%);}}
.ls-timeline{display:flex;gap:0;position:relative;margin-top:64px;}.ls-timeline::before{content:'';position:absolute;top:24px;left:0;right:0;height:2px;background:var(--color-light);}.ls-timeline-step{flex:1;text-align:center;position:relative;padding:0 16px;}.ls-timeline-num{width:48px;height:48px;border-radius:50%;background:var(--color-primary);color:var(--color-dark);font-size:16px;font-weight:800;display:flex;align-items:center;justify-content:center;margin:0 auto 20px;position:relative;z-index:1;}.ls-timeline-title{font-size:16px;font-weight:700;margin-bottom:8px;}.ls-timeline-desc{font-size:14px;color:var(--color-gray);line-height:1.5;}@media(max-width:800px){.ls-timeline{flex-direction:column;gap:32px;}.ls-timeline::before{display:none;}}
.ls-testimonial-card{text-align:center;max-width:700px;margin:0 auto;transition:opacity 0.5s ease;}.ls-testimonial-quote{font-size:clamp(18px,2.5vw,24px);font-weight:400;line-height:1.6;color:var(--color-dark);margin-bottom:32px;font-style:italic;}.ls-testimonial-name{font-size:16px;font-weight:700;}.ls-testimonial-role{font-size:14px;color:var(--color-gray);}.ls-testimonial-dots{display:flex;gap:8px;justify-content:center;margin-top:32px;}.ls-testimonial-dot{width:10px;height:10px;border-radius:50%;background:#ddd;cursor:pointer;transition:background 0.3s ease;}.ls-testimonial-dot.active{background:var(--color-primary);}
.ls-featured-img{width:100%;border-radius:16px;height:400px;object-fit:cover;}.ls-featured-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;margin:32px 0;}.ls-featured-stat-num{font-size:36px;font-weight:800;color:var(--color-primary);line-height:1;}.ls-featured-stat-label{font-size:13px;color:rgba(255,255,255,0.5);margin-top:4px;text-transform:uppercase;letter-spacing:0.08em;}
#ls-footer{background:var(--color-dark);color:#fff;padding:80px 0 40px;}.ls-footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:48px;margin-bottom:60px;}.ls-footer-brand{font-size:20px;font-weight:800;margin-bottom:16px;letter-spacing:-0.02em;}.ls-footer-brand span{color:var(--color-primary);}.ls-footer-desc{font-size:14px;color:rgba(255,255,255,0.5);line-height:1.6;max-width:300px;}.ls-footer-heading{font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:20px;color:rgba(255,255,255,0.4);}.ls-footer-links{list-style:none;}.ls-footer-links li{margin-bottom:12px;}.ls-footer-links a{font-size:15px;color:rgba(255,255,255,0.7);transition:color 0.3s ease;cursor:pointer;}.ls-footer-links a:hover{color:var(--color-primary);}.ls-footer-bottom{border-top:1px solid rgba(255,255,255,0.08);padding-top:24px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:16px;}.ls-footer-copy{font-size:13px;color:rgba(255,255,255,0.3);}.ls-footer-socials{display:flex;gap:16px;}.ls-footer-socials a{width:36px;height:36px;border-radius:50%;background:rgba(255,255,255,0.06);display:flex;align-items:center;justify-content:center;font-size:14px;color:rgba(255,255,255,0.5);transition:all 0.3s ease;}.ls-footer-socials a:hover{background:var(--color-primary);color:var(--color-dark);}@media(max-width:800px){.ls-footer-grid{grid-template-columns:1fr 1fr;}}@media(max-width:500px){.ls-footer-grid{grid-template-columns:1fr;}}
#ls-sticky-cta{position:fixed;bottom:0;left:0;right:0;background:rgba(26,26,26,0.92);backdrop-filter:blur(16px);padding:16px 32px;display:flex;align-items:center;justify-content:center;gap:24px;z-index:9998;transform:translateY(100%);transition:transform 0.5s var(--transition-smooth);border-top:1px solid rgba(255,255,255,0.06);}#ls-sticky-cta.show{transform:translateY(0);}#ls-sticky-cta p{color:rgba(255,255,255,0.8);font-size:15px;font-weight:500;}#ls-sticky-cta.ls-sticky-btn{background:var(--color-primary);color:var(--color-dark);font-weight:700;padding:10px 24px;border-radius:8px;font-size:14px;white-space:nowrap;transition:transform 0.3s ease;}#ls-sticky-cta.ls-sticky-btn:hover{transform:translateY(-2px);}#ls-sticky-cta.ls-sticky-close{background:none;border:none;color:rgba(255,255,255,0.4);font-size:20px;cursor:pointer;padding:4px 8px;transition:color 0.3s ease;}#ls-sticky-cta.ls-sticky-close:hover{color:#fff;}@media(max-width:600px){#ls-sticky-cta{flex-wrap:wrap;gap:12px;padding:14px 20px;}#ls-sticky-cta p{font-size:13px;flex:1;}}
.ls-form-group{margin-bottom:20px;}.ls-form-label{display:block;font-size:14px;font-weight:600;margin-bottom:8px;color:var(--color-dark);}.ls-form-input,.ls-form-select,.ls-form-textarea{width:100%;padding:14px 16px;border:2px solid#E8E8E8;border-radius:10px;background:#fff;font-size:16px;transition:border-color 0.3s ease;color:var(--color-dark);}.ls-form-input:focus,.ls-form-select:focus,.ls-form-textarea:focus{outline:none;border-color:var(--color-primary);}.ls-form-textarea{min-height:120px;resize:vertical;}
.ls-calc-progress{display:flex;gap:8px;margin-bottom:48px;}.ls-calc-progress-step{flex:1;height:4px;border-radius:2px;background:#E8E8E8;transition:background 0.4s ease;}.ls-calc-progress-step.active{background:var(--color-primary);}.ls-calc-step{display:none;}.ls-calc-step.active{display:block;}.ls-calc-step h3{font-size:28px;font-weight:800;margin-bottom:8px;}.ls-calc-step p{font-size:16px;color:var(--color-gray);margin-bottom:32px;}.ls-calc-nav{display:flex;gap:16px;margin-top:32px;}
.ls-results-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;margin:48px 0;}.ls-result-card{background:var(--color-dark);border-radius:16px;padding:32px;text-align:center;}.ls-result-num{font-size:42px;font-weight:800;color:var(--color-primary);letter-spacing:-0.03em;line-height:1;margin-bottom:8px;}.ls-result-label{font-size:14px;color:rgba(255,255,255,0.5);text-transform:uppercase;letter-spacing:0.08em;}@media(max-width:700px){.ls-results-grid{grid-template-columns:1fr;}}
.ls-accordion{border:1px solid#E8E8E8;border-radius:12px;overflow:hidden;margin-bottom:12px;}.ls-accordion-header{padding:20px 24px;display:flex;justify-content:space-between;align-items:center;cursor:pointer;font-weight:600;font-size:17px;background:#fff;transition:background 0.3s ease;}.ls-accordion-header:hover{background:var(--color-light);}.ls-accordion-icon{font-size:20px;transition:transform 0.3s ease;color:var(--color-gray);}.ls-accordion.open.ls-accordion-icon{transform:rotate(45deg);}.ls-accordion-body{max-height:0;overflow:hidden;transition:max-height 0.4s var(--transition-smooth);padding:0 24px;font-size:15px;color:var(--color-gray);line-height:1.7;}.ls-accordion.open.ls-accordion-body{max-height:500px;padding:0 24px 20px;}
.ls-compare-table{width:100%;border-collapse:collapse;margin-top:32px;}.ls-compare-table th{padding:16px 20px;text-align:left;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.08em;color:var(--color-gray);border-bottom:2px solid var(--color-light);}.ls-compare-table td{padding:16px 20px;border-bottom:1px solid var(--color-light);font-size:15px;}.ls-compare-table tr:last-child td{border-bottom:none;}.ls-compare-highlight{color:var(--color-primary);font-weight:700;}
.ls-before-after{display:grid;grid-template-columns:1fr 1fr;gap:4px;border-radius:16px;overflow:hidden;}.ls-ba-panel{position:relative;height:300px;}.ls-ba-panel img{width:100%;height:100%;object-fit:cover;}.ls-ba-label{position:absolute;bottom:16px;left:16px;background:rgba(0,0,0,0.7);color:#fff;padding:6px 14px;border-radius:6px;font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:0.08em;}@media(max-width:600px){.ls-before-after{grid-template-columns:1fr;}}
.ls-lazy{background:var(--color-light);transition:opacity 0.6s ease;}.ls-lazy.loaded{opacity:1;}
.ls-legal h2{font-size:28px;font-weight:700;margin:40px 0 16px;}.ls-legal h3{font-size:20px;font-weight:600;margin:32px 0 12px;}.ls-legal p{margin-bottom:16px;color:var(--color-gray);}.ls-legal ul{margin-bottom:16px;padding-left:24px;color:var(--color-gray);}.ls-legal li{margin-bottom:8px;}`;document.head.appendChild(style);}
let observer;function initObserver(){observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const delay=entry.target.dataset.delay||0;setTimeout(()=>entry.target.classList.add('visible'),delay);observer.unobserve(entry.target);}});},{threshold:0.1,rootMargin:'0px 0px -40px 0px'});}
function observe(root){if(!observer)initObserver();(root||document).querySelectorAll('.ls-reveal, .ls-reveal-left, .ls-reveal-right').forEach(el=>{observer.observe(el);});}
function animateCounters(root){const counterObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const el=entry.target;const id=el.dataset.counterId||Math.random().toString(36);if(countersAnimated[id])return;countersAnimated[id]=true;const target=parseFloat(el.dataset.target);const prefix=el.dataset.prefix||'';const suffix=el.dataset.suffix||'';const decimals=el.dataset.decimals?parseInt(el.dataset.decimals):0;const duration=2000;const start=performance.now();const easeOutExpo=t=>t===1?1:1-Math.pow(2,-10*t);function tick(now){const elapsed=now-start;const progress=Math.min(elapsed/duration,1);const eased=easeOutExpo(progress);const current=eased*target;el.textContent=prefix+(decimals>0?current.toFixed(decimals):Math.round(current).toLocaleString())+suffix;if(progress<1)requestAnimationFrame(tick);}
requestAnimationFrame(tick);counterObserver.unobserve(el);}});},{threshold:0.3});(root||document).querySelectorAll('[data-counter]').forEach(el=>counterObserver.observe(el));}
function lazyLoad(root){const imgObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target;if(img.dataset.src){img.src=img.dataset.src;img.onload=()=>img.classList.add('loaded');}
imgObserver.unobserve(img);}});},{rootMargin:'200px'});(root||document).querySelectorAll('.ls-lazy[data-src]').forEach(img=>imgObserver.observe(img));}
function setMeta(title,desc){document.title=title+' | LED Solutions';let meta=$('meta[name="description"]');if(!meta){meta=el('meta',{name:'description'});document.head.appendChild(meta);}
meta.setAttribute('content',desc);}
function renderNav(){const nav=el('nav',{id:'ls-nav',className:'dark-hero'});nav.innerHTML=`<div class="ls-nav-inner"><div class="ls-nav-logo"onclick="location.hash='#/'">LED<span>.</span>Solutions</div><div class="ls-nav-links"><a class="ls-nav-link"data-route="#/services">Services</a><a class="ls-nav-link"data-route="#/case-studies">Case Studies</a><a class="ls-nav-link"data-route="#/industries">Industries</a><a class="ls-nav-link"data-route="#/about">About</a><a class="ls-nav-link"data-route="#/contact">Contact</a><a class="ls-nav-cta"data-route="#/calculator">Get Free Audit</a></div><button class="ls-hamburger"aria-label="Menu"><span></span><span></span><span></span></button></div>`;return nav;}
function renderMobileMenu(){const menu=el('div',{id:'ls-mobile-menu',className:'ls-mobile-menu'});const links=[['#/','Home'],['#/services','Services'],['#/case-studies','Case Studies'],['#/industries','Industries'],['#/about','About'],['#/contact','Contact'],['#/calculator','Free Energy Audit'],];links.forEach(([href,label])=>{const a=el('a',{},label);a.addEventListener('click',()=>{menu.classList.remove('open');navigate(href);});menu.appendChild(a);});return menu;}
function renderFooter(){const footer=el('footer',{id:'ls-footer'});footer.innerHTML=`<div class="ls-container"><div class="ls-footer-grid"><div><div class="ls-footer-brand">LED<span>.</span>Solutions</div><p class="ls-footer-desc">Commercial&industrial LED retrofit specialists serving the Southeast United States.Engineering-grade solutions backed by verified results.</p></div><div><div class="ls-footer-heading">Services</div><ul class="ls-footer-links"><li><a onclick="navigate('#/retrofit')">LED Retrofit</a></li><li><a onclick="navigate('#/controls')">Smart Controls</a></li><li><a onclick="navigate('#/rebates')">Rebate Management</a></li><li><a onclick="navigate('#/calculator')">Free Energy Audit</a></li></ul></div><div><div class="ls-footer-heading">Company</div><ul class="ls-footer-links"><li><a onclick="navigate('#/about')">About Us</a></li><li><a onclick="navigate('#/case-studies')">Case Studies</a></li><li><a onclick="navigate('#/industries')">Industries</a></li><li><a onclick="navigate('#/contact')">Contact</a></li></ul></div><div><div class="ls-footer-heading">Contact</div><ul class="ls-footer-links"><li><a href="mailto:${CONFIG.email}">${CONFIG.email}</a></li><li><a>${CONFIG.phone}</a></li><li><a onclick="navigate('#/privacy')">Privacy Policy</a></li><li><a onclick="navigate('#/terms')">Terms of Service</a></li></ul></div></div><div class="ls-footer-bottom"><div class="ls-footer-copy">&copy;${new Date().getFullYear()}LED Solutions.All rights reserved.</div><div class="ls-footer-socials"><a href="#"aria-label="Instagram">IG</a><a href="#"aria-label="Facebook">FB</a><a href="#"aria-label="YouTube">YT</a><a href="#"aria-label="LinkedIn">LI</a></div></div></div>`;return footer;}
function renderStickyCTA(){const bar=el('div',{id:'ls-sticky-cta'});bar.innerHTML=`<p>How much is your lighting costing you?</p><button class="ls-sticky-btn"onclick="navigate('#/calculator')">Take the 2-min quiz \u2192</button><button class="ls-sticky-close"aria-label="Close">\u00D7</button>`;return bar;}
function renderScrollProgress(){return el('div',{id:'ls-scroll-progress'});}
function pageHero(title,subtitle,bgImg){return`<section class="ls-page-hero"><div class="ls-hero-bg"style="background-image:url('${bgImg}')"></div><div class="ls-hero-content"><div class="ls-hero-sub ls-reveal">${CONFIG.brand}</div><h1 class="ls-reveal"data-delay="100">${title}</h1>${subtitle?`<p class="ls-reveal"data-delay="200">${subtitle}</p>`:''}</div></section>`;}
function ctaBand(headline,btnText,route){return`<section class="ls-section green"style="padding:80px 0;"><div class="ls-container"style="text-align:center;"><h2 class="ls-reveal"style="font-size:clamp(28px,4vw,44px);font-weight:800;color:var(--color-dark);letter-spacing:-0.02em;margin-bottom:24px;">${headline||'Ready to Stop Wasting Energy?'}</h2><button class="ls-btn ls-btn-dark ls-reveal"data-delay="100"onclick="navigate('${route || '#/calculator'}')">${btnText||'Calculate Your Savings'}\u2192</button></div></section>`;}
function renderHomepage(){setMeta('Commercial LED Retrofit & Energy Solutions','LED Solutions delivers turnkey LED retrofit and smart controls for commercial buildings. $12.4M+ in verified client savings across the Southeast US.');const logoItems=Array(16).fill(0).map(()=>'<div class="ls-marquee-item"></div>').join('');return`<!--HERO--><section class="ls-hero"><div class="ls-hero-bg"style="background-image:url('${IMAGES.hero}')"></div><div class="ls-hero-content"><div class="ls-hero-sub ls-reveal">Commercial LED Retrofit Specialists</div><h1 class="ls-reveal"data-delay="150">We Work.<br>You Save.</h1><p class="ls-reveal"data-delay="300">Turnkey LED retrofit and smart controls for commercial&amp;industrial buildings.Engineering-grade solutions that pay for themselves.</p><div class="ls-hero-actions ls-reveal"data-delay="450"><button class="ls-btn-primary"onclick="navigate('#/calculator')">Calculate Your Savings \u2192</button><button class="ls-btn-outline"onclick="navigate('#/case-studies')">See Our Work</button></div><div class="ls-reveal"data-delay="600"style="margin-top:48px;"><span data-counter data-target="12.4"data-prefix="$"data-suffix="M+"data-decimals="1"data-counter-id="hero-savings"style="font-size:32px;font-weight:800;color:var(--color-primary);">$0M+</span><div style="font-size:14px;color:rgba(255,255,255,0.5);margin-top:4px;">in verified client savings</div></div></div><div class="ls-scroll-hint"><svg viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg></div></section><!--LOGO MARQUEE--><div class="ls-marquee-wrap"><div class="ls-marquee">${logoItems}${logoItems}</div></div><!--PROOF STATS--><section class="ls-section"style="padding:100px 0;"><div class="ls-container"><div class="ls-stats-row"><div class="ls-reveal"data-delay="0"><div class="ls-stat-num"data-counter data-target="147"data-suffix="+"data-counter-id="stat1">0</div><div class="ls-stat-label">Projects Completed</div></div><div class="ls-reveal"data-delay="100"><div class="ls-stat-num"data-counter data-target="68"data-suffix="%"data-counter-id="stat2">0</div><div class="ls-stat-label">Avg Energy Reduction</div></div><div class="ls-reveal"data-delay="200"><div class="ls-stat-num"data-counter data-target="2.1"data-prefix="$"data-suffix="M+"data-decimals="1"data-counter-id="stat3">$0</div><div class="ls-stat-label">Rebates Captured</div></div><div class="ls-reveal"data-delay="300"><div class="ls-stat-num"data-counter data-target="18"data-suffix=" Mo"data-counter-id="stat4">0</div><div class="ls-stat-label">Avg Payback Period</div></div></div></div></section><!--SERVICES--><section class="ls-section light"><div class="ls-container"><div class="ls-section-label ls-reveal">What We Do</div><h2 class="ls-section-title ls-reveal"data-delay="100">Lighting that pays<br>for itself.</h2><p class="ls-section-subtitle ls-reveal"data-delay="150"style="margin-bottom:64px;">From audit to install to rebate capture — one partner handles everything.</p><div class="ls-grid-3">${SERVICES.slice(0,3).map((s,i)=>`<div class="ls-card ls-reveal"data-delay="${i * 100 + 200}"onclick="navigate('#/${s.id === 'retrofit' ? 'retrofit' : s.id === 'controls' ? 'controls' : 'rebates'}')"><div class="ls-card-img-wrap"><img class="ls-card-img ls-lazy"data-src="${s.img}"alt="${s.title}"></div><div class="ls-card-body"><div class="ls-card-stat">${s.stat}</div><div class="ls-card-stat-label"style="margin-bottom:12px;">${s.statLabel}</div><h3 class="ls-card-title">${s.title}</h3><p class="ls-card-text">${s.short}</p><span class="ls-text-link">Learn More \u2192</span></div></div>`).join('')}</div><div style="text-align:center;margin-top:48px;"class="ls-reveal"data-delay="500"><button class="ls-btn ls-btn-outline-dark"onclick="navigate('#/services')">View All Services \u2192</button></div></div></section><!--FEATURED CASE STUDY--><section class="ls-section dark"><div class="ls-container"><div class="ls-grid-60-40"><div class="ls-reveal-left"><img class="ls-featured-img ls-lazy"data-src="${CASE_STUDIES[0].img}"alt="${CASE_STUDIES[0].title}"></div><div class="ls-reveal-right"><div class="ls-section-label">Featured Project</div><h2 style="font-size:clamp(28px,4vw,40px);font-weight:800;margin-bottom:16px;letter-spacing:-0.02em;">${CASE_STUDIES[0].title}</h2><p style="color:rgba(255,255,255,0.6);margin-bottom:32px;">${CASE_STUDIES[0].type}&bull;${CASE_STUDIES[0].sqft}SF&bull;${CASE_STUDIES[0].fixtures}Fixtures</p><div class="ls-featured-stats"><div><div class="ls-featured-stat-num">${CASE_STUDIES[0].reduction}%</div><div class="ls-featured-stat-label">Energy Reduction</div></div><div><div class="ls-featured-stat-num">${CASE_STUDIES[0].savings}</div><div class="ls-featured-stat-label">Annual Savings</div></div><div><div class="ls-featured-stat-num">${CASE_STUDIES[0].payback}yr</div><div class="ls-featured-stat-label">Payback Period</div></div></div><a class="ls-text-link"style="color:#fff;"onclick="navigate('#/case-study/${CASE_STUDIES[0].id}')">Read Full Case Study \u2192</a></div></div></div></section><!--HOW WE WORK--><section class="ls-section"><div class="ls-container"><div style="text-align:center;"><div class="ls-section-label ls-reveal">Our Process</div><h2 class="ls-section-title ls-reveal"data-delay="100">How we work.</h2><p class="ls-section-subtitle ls-reveal"data-delay="150"style="margin:0 auto;">Five steps from assessment to verified savings.</p></div><div class="ls-timeline">${PROCESS_STEPS.map((s,i)=>`<div class="ls-timeline-step ls-reveal"data-delay="${i * 120}"><div class="ls-timeline-num">${s.num}</div><div class="ls-timeline-title">${s.title}</div><div class="ls-timeline-desc">${s.desc}</div></div>`).join('')}</div></div></section><!--TESTIMONIALS--><section class="ls-section light"id="ls-testimonials-section"><div class="ls-container"style="text-align:center;"><div class="ls-section-label ls-reveal">Testimonials</div><h2 class="ls-section-title ls-reveal"data-delay="100"style="margin-bottom:48px;">What our clients say.</h2><div style="font-size:64px;color:var(--color-primary);line-height:1;margin-bottom:24px;"class="ls-reveal"data-delay="150">\u201C</div><div id="ls-testimonial-container"class="ls-reveal"data-delay="200"></div></div></section><!--CTA BAND-->${ctaBand()}`;}
function renderServicesPage(){setMeta('Our Services','LED retrofit, smart controls, rebate management, sports lighting, and more. Comprehensive commercial lighting solutions.');return`${pageHero('Our Services','Comprehensive commercial lighting solutions — from audit to verified savings.',IMAGES.services)}<section class="ls-section"><div class="ls-container"><div class="ls-grid-3">${SERVICES.map((s,i)=>`<div class="ls-card ls-reveal"data-delay="${i * 100}"onclick="navigate('#/${s.id === 'retrofit' ? 'retrofit' : s.id === 'controls' ? 'controls' : s.id === 'rebates' ? 'rebates' : 'services'}')"><div class="ls-card-img-wrap"><img class="ls-card-img ls-lazy"data-src="${s.img}"alt="${s.title}"></div><div class="ls-card-body"><div style="font-size:32px;margin-bottom:12px;">${s.icon}</div><h3 class="ls-card-title">${s.title}</h3><p class="ls-card-text">${s.short}</p><span class="ls-text-link">Learn More \u2192</span></div></div>`).join('')}</div></div></section>${ctaBand('Ready to see what\'s possible?','Schedule Free Audit','#/calculator')}`;}
function renderRetrofitPage(){setMeta('Commercial LED Retrofit','Cut energy costs 50-70% with turnkey LED retrofits. From audit to install — one partner, one outcome.');return`${pageHero('Commercial LED Retrofit','Cut energy costs 50\u201370%. Turnkey LED retrofits from audit to install.',IMAGES.industrial)}<section class="ls-section"><div class="ls-container"><div class="ls-grid-40-60"><div class="ls-reveal-left"><div class="ls-section-label">Service Overview</div><h2 class="ls-section-title">One partner.<br>One outcome.</h2><p class="ls-section-subtitle"style="margin-bottom:24px;">We handle every detail of your LED retrofit — engineering,procurement,installation,commissioning,and rebate capture.You get a turnkey project that pays for itself.</p><p style="color:var(--color-gray);">Our engineering team designs custom solutions for each facility,optimizing fixture placement,light levels,and control strategies to maximize both energy savings and occupant comfort.</p></div><div class="ls-reveal-right"><img class="ls-lazy"data-src="${IMAGES.industrial}"alt="LED Retrofit"style="border-radius:16px;width:100%;height:400px;object-fit:cover;"></div></div></div></section><section class="ls-section light"><div class="ls-container"><div style="text-align:center;margin-bottom:48px;"><div class="ls-section-label ls-reveal">Applications</div><h2 class="ls-section-title ls-reveal"data-delay="100">Where we work.</h2></div><div class="ls-grid-3">${['Office buildings & corporate campuses','Warehouses & distribution centers','Retail stores & shopping centers','Healthcare facilities','Educational institutions','Parking structures & exteriors'].map((a,i)=>`<div class="ls-card ls-reveal"data-delay="${i*80}"style="cursor:default;"><div class="ls-card-body"style="padding:24px;"><h3 style="font-size:17px;font-weight:600;">${a}</h3></div></div>`).join('')}</div></div></section><section class="ls-section"><div class="ls-container"><div style="text-align:center;margin-bottom:48px;"><div class="ls-section-label ls-reveal">The Difference</div><h2 class="ls-section-title ls-reveal"data-delay="100">LED Solutions vs.Typical Contractor</h2></div><div class="ls-reveal"data-delay="200"style="overflow-x:auto;"><table class="ls-compare-table"><thead><tr><th>Capability</th><th>LED Solutions</th><th>Typical Contractor</th></tr></thead><tbody><tr><td>Engineering Assessment</td><td class="ls-compare-highlight">Detailed photometric analysis</td><td>Visual walkthrough</td></tr><tr><td>ROI Analysis</td><td class="ls-compare-highlight">Verified M&V methodology</td><td>Rough estimate</td></tr><tr><td>Rebate Management</td><td class="ls-compare-highlight">Full-service capture($2.1M+secured)</td><td>Basic paperwork help</td></tr><tr><td>Controls Integration</td><td class="ls-compare-highlight">BAS integration&commissioning</td><td>Basic switching</td></tr><tr><td>Post-Install Verification</td><td class="ls-compare-highlight">30/60/90 day measurement</td><td>Final walkthrough only</td></tr><tr><td>Warranty Support</td><td class="ls-compare-highlight">Dedicated support team</td><td>Manufacturer referral</td></tr></tbody></table></div></div></section>${ctaBand('See how much you could save.','Get Your Free Audit','#/calculator')}`;}
function renderControlsPage(){setMeta('Smart Lighting Controls','20-40% additional savings beyond LED. Occupancy sensing, daylight harvesting, scheduling, and BAS integration.');const controlTypes=[{title:'Occupancy & Vacancy Sensing',desc:'Lights respond to presence automatically. Rooms and zones turn off when empty, eliminating wasted energy from lights left on in unoccupied spaces.'},{title:'Daylight Harvesting',desc:'Photosensors dim artificial lighting when natural daylight is available, maintaining consistent light levels while reducing energy consumption.'},{title:'Scheduling & Time-of-Day',desc:'Automated schedules ensure lights operate only when needed. Holiday schedules, after-hours modes, and sweep-off capabilities built in.'},{title:'BAS / BMS Integration',desc:'Full integration with your building automation system for centralized monitoring, control, and energy reporting across all lighting zones.'},{title:'Task Tuning & Zoning',desc:'Fine-tune light levels for specific tasks and zones. Reduce over-lighting in areas that don\'t need full output.'},];return`${pageHero('Smart Controls & Integration','20\u201340% additional savings beyond LED retrofit.',IMAGES.controls)}<section class="ls-section"><div class="ls-container"><div class="ls-grid-60-40"><div class="ls-reveal-left"><div class="ls-section-label">Beyond LED</div><h2 class="ls-section-title">The smartest buildings<br>save the most.</h2><p class="ls-section-subtitle"style="margin-bottom:24px;">LED retrofit alone delivers 50\u201370%savings.Add smart controls and you unlock an additional 20\u201340%reduction.Combined,facilities see 70\u201385%total energy savings on lighting.</p></div><div class="ls-reveal-right"style="text-align:center;"><div style="display:inline-block;background:var(--color-dark);border-radius:16px;padding:40px;text-align:left;"><div style="margin-bottom:24px;"><div style="font-size:14px;color:rgba(255,255,255,0.5);margin-bottom:8px;">LED Retrofit Alone</div><div style="background:rgba(255,255,255,0.1);border-radius:8px;height:24px;overflow:hidden;"><div style="width:65%;height:100%;background:var(--color-primary);border-radius:8px;"></div></div><div style="font-size:14px;color:var(--color-primary);margin-top:4px;">50\u201370%savings</div></div><div><div style="font-size:14px;color:rgba(255,255,255,0.5);margin-bottom:8px;">LED+Smart Controls</div><div style="background:rgba(255,255,255,0.1);border-radius:8px;height:24px;overflow:hidden;"><div style="width:85%;height:100%;background:var(--color-primary);border-radius:8px;"></div></div><div style="font-size:14px;color:var(--color-primary);margin-top:4px;">70\u201385%savings</div></div></div></div></div></div></section><section class="ls-section light"><div class="ls-container"><div style="text-align:center;margin-bottom:48px;"><div class="ls-section-label ls-reveal">Control Types</div><h2 class="ls-section-title ls-reveal"data-delay="100">How smart controls work.</h2></div>${controlTypes.map((c,i)=>`<div class="ls-accordion ls-reveal"data-delay="${i*80}"><div class="ls-accordion-header"onclick="this.parentElement.classList.toggle('open')">${c.title}<span class="ls-accordion-icon">+</span></div><div class="ls-accordion-body"><p>${c.desc}</p></div></div>`).join('')}</div></section>${ctaBand('See combined savings for your facility.','Calculate Savings','#/calculator')}`;}
function renderRebatesPage(){setMeta('Utility Rebate Management','$2.1M+ in rebates captured. We identify, apply for, and secure every rebate dollar available for your LED project.');return`${pageHero('Utility Rebate Management','$2.1M+ captured for our clients. We handle everything.',IMAGES.cre)}<section class="ls-section"><div class="ls-container"style="text-align:center;"><div class="ls-section-label ls-reveal">How It Works</div><h2 class="ls-section-title ls-reveal"data-delay="100"style="margin-bottom:64px;">Three steps to maximum rebates.</h2><div class="ls-grid-3">${[{num:'01',title:'Identify',desc:'We research every federal, state, and utility rebate program available for your project and location.'},{num:'02',title:'Apply',desc:'We prepare and submit all paperwork, pre-approvals, and documentation required by each program.'},{num:'03',title:'Capture',desc:'We track every application through approval, ensuring maximum payout. Average capture: $67K per project.'},].map((s,i)=>`<div class="ls-card ls-reveal"data-delay="${i*120}"style="cursor:default;"><div class="ls-card-body"style="text-align:center;padding:40px 28px;"><div style="font-size:48px;font-weight:800;color:var(--color-primary);margin-bottom:16px;">${s.num}</div><h3 class="ls-card-title">${s.title}</h3><p class="ls-card-text">${s.desc}</p></div></div>`).join('')}</div></div></section><section class="ls-section dark"><div class="ls-container"><div class="ls-stats-row"><div class="ls-reveal"><div class="ls-stat-num"data-counter data-target="2.1"data-prefix="$"data-suffix="M+"data-decimals="1"data-counter-id="reb1">$0</div><div class="ls-stat-label">Total Captured</div></div><div class="ls-reveal"data-delay="100"><div class="ls-stat-num"data-counter data-target="147"data-suffix="+"data-counter-id="reb2">0</div><div class="ls-stat-label">Projects</div></div><div class="ls-reveal"data-delay="200"><div class="ls-stat-num">$67K</div><div class="ls-stat-label">Avg Per Project</div></div><div class="ls-reveal"data-delay="300"><div class="ls-stat-num">100%</div><div class="ls-stat-label">Managed For You</div></div></div></div></section>${ctaBand('Don\'t leave money on the table.','Check Your Rebate Eligibility','#/calculator')}`;}
function renderCaseStudiesPage(){setMeta('Case Studies','Real results from real projects. See verified savings across commercial offices, warehouses, retail, and healthcare.');return`${pageHero('Case Studies','Real results. Verified savings. No asterisks.',IMAGES.cre)}<section class="ls-section"><div class="ls-container"><div class="ls-grid-2">${CASE_STUDIES.map((cs,i)=>`<div class="ls-card ls-reveal"data-delay="${i*120}"onclick="navigate('#/case-study/${cs.id}')"style="cursor:pointer;"><div class="ls-card-img-wrap"><img class="ls-card-img ls-lazy"data-src="${cs.img}"alt="${cs.title}"style="height:260px;"></div><div class="ls-card-body"><div style="display:flex;gap:16px;margin-bottom:16px;"><div><div class="ls-card-stat">${cs.reduction}%</div><div class="ls-card-stat-label">Reduction</div></div><div><div class="ls-card-stat">${cs.savings}</div><div class="ls-card-stat-label">Annual Savings</div></div><div><div class="ls-card-stat">${cs.payback}yr</div><div class="ls-card-stat-label">Payback</div></div></div><h3 class="ls-card-title">${cs.title}</h3><p class="ls-card-text">${cs.type}&bull;${cs.sqft}SF&bull;${cs.fixtures}Fixtures</p><span class="ls-text-link">Read Case Study \u2192</span></div></div>`).join('')}</div></div></section>${ctaBand()}`;}
function renderCaseStudyPage(id){const cs=CASE_STUDIES.find(c=>c.id===id)||CASE_STUDIES[0];setMeta(cs.title,`${cs.type}:${cs.reduction}%energy reduction,${cs.annualSavings}annual savings,${cs.payback}-year payback.`);return`${pageHero(cs.title,cs.type+' \u2014 '+cs.sqft+' SF',cs.img)}<section class="ls-section dark"style="padding:60px 0;"><div class="ls-container"><div class="ls-stats-row"><div class="ls-reveal"><div class="ls-stat-num">${cs.sqft}</div><div class="ls-stat-label">Square Feet</div></div><div class="ls-reveal"data-delay="100"><div class="ls-stat-num"style="color:var(--color-primary);">${cs.reduction}%</div><div class="ls-stat-label">Energy Reduction</div></div><div class="ls-reveal"data-delay="200"><div class="ls-stat-num"style="color:var(--color-primary);">${cs.savings}</div><div class="ls-stat-label">Annual Savings</div></div><div class="ls-reveal"data-delay="300"><div class="ls-stat-num">${cs.payback}yr</div><div class="ls-stat-label">Payback</div></div></div></div></section><section class="ls-section"><div class="ls-container"style="max-width:800px;"><div class="ls-reveal"><div class="ls-section-label">The Challenge</div><p style="font-size:18px;line-height:1.8;color:var(--color-gray);margin-bottom:48px;">${cs.desc}</p></div><div class="ls-reveal"data-delay="100"><div class="ls-section-label">Results</div><ul style="list-style:none;padding:0;">${cs.results.map(r=>`<li style="padding:12px 0;border-bottom:1px solid var(--color-light);font-size:16px;display:flex;align-items:center;gap:12px;"><span style="color:var(--color-primary);font-size:20px;">&#10003;</span>${r}</li>`).join('')}</ul></div></div></section><section class="ls-section light"><div class="ls-container"><div style="text-align:center;margin-bottom:32px;"><div class="ls-section-label ls-reveal">Visual Impact</div><h2 class="ls-section-title ls-reveal"data-delay="100">Before&After</h2></div><div class="ls-before-after ls-reveal"data-delay="200"><div class="ls-ba-panel"><img class="ls-lazy"data-src="${IMAGES.beforeDim}"alt="Before"><div class="ls-ba-label">Before</div></div><div class="ls-ba-panel"><img class="ls-lazy"data-src="${IMAGES.afterBright}"alt="After"><div class="ls-ba-label">After</div></div></div></div></section>${ctaBand('Want results like these?','Request Your Free Audit','#/calculator')}`;}
function renderCalculatorPage(){setMeta('Savings Calculator','Estimate your LED retrofit savings in 2 minutes. Get projected energy reduction, rebate estimates, and payback period.');return`<section class="ls-section"style="padding-top:calc(var(--nav-height) + 60px);min-height:100vh;"><div class="ls-container"style="max-width:680px;"><div style="text-align:center;margin-bottom:48px;"><div class="ls-section-label ls-reveal">Savings Calculator</div><h2 class="ls-section-title ls-reveal"data-delay="100">How much could<br>you save?</h2><p class="ls-section-subtitle ls-reveal"data-delay="150"style="margin:0 auto;">Answer 4 quick questions for an instant savings estimate.</p></div><div class="ls-calc-progress ls-reveal"data-delay="200"><div class="ls-calc-progress-step active"data-step="1"></div><div class="ls-calc-progress-step"data-step="2"></div><div class="ls-calc-progress-step"data-step="3"></div><div class="ls-calc-progress-step"data-step="4"></div></div><div id="ls-calc-form"class="ls-reveal"data-delay="250"><!--Step 1--><div class="ls-calc-step active"data-step="1"><h3>About your facility</h3><p>What type of building are you lighting?</p><div class="ls-form-group"><label class="ls-form-label">Facility Type</label><select class="ls-form-select"id="calc-facility"><option value="">Select type...</option><option value="office">Office Building</option><option value="warehouse">Warehouse/Distribution</option><option value="retail">Retail/Shopping Center</option><option value="healthcare">Healthcare Facility</option><option value="education">Education/Campus</option><option value="industrial">Industrial/Manufacturing</option><option value="other">Other</option></select></div><div class="ls-form-group"><label class="ls-form-label">Square Footage</label><input type="number"class="ls-form-input"id="calc-sqft"placeholder="e.g. 50000"></div><div class="ls-calc-nav"><button class="ls-btn ls-btn-primary-std"onclick="calcNext(2)">Next \u2192</button></div></div><!--Step 2--><div class="ls-calc-step"data-step="2"><h3>Current lighting</h3><p>Tell us about your existing system.</p><div class="ls-form-group"><label class="ls-form-label">Primary Lighting Type</label><select class="ls-form-select"id="calc-lighting"><option value="">Select type...</option><option value="fluorescent">Fluorescent(T8/T12)</option><option value="hid">HID/Metal Halide</option><option value="halogen">Halogen</option><option value="mixed">Mixed/Unknown</option><option value="led-old">Older LED(5+years)</option></select></div><div class="ls-form-group"><label class="ls-form-label">Daily Operating Hours</label><input type="number"class="ls-form-input"id="calc-hours"placeholder="e.g. 12"></div><div class="ls-calc-nav"><button class="ls-btn ls-btn-outline-dark"onclick="calcNext(1)">\u2190 Back</button><button class="ls-btn ls-btn-primary-std"onclick="calcNext(3)">Next \u2192</button></div></div><!--Step 3--><div class="ls-calc-step"data-step="3"><h3>Energy details</h3><p>Help us estimate your current costs.</p><div class="ls-form-group"><label class="ls-form-label">Approximate Number of Fixtures</label><input type="number"class="ls-form-input"id="calc-fixtures"placeholder="e.g. 500"></div><div class="ls-form-group"><label class="ls-form-label">Utility Rate($/kWh)</label><input type="number"step="0.01"class="ls-form-input"id="calc-rate"placeholder="e.g. 0.12"value="0.12"></div><div class="ls-calc-nav"><button class="ls-btn ls-btn-outline-dark"onclick="calcNext(2)">\u2190 Back</button><button class="ls-btn ls-btn-primary-std"onclick="calcNext(4)">Next \u2192</button></div></div><!--Step 4--><div class="ls-calc-step"data-step="4"><h3>Get your results</h3><p>Where should we send your detailed proposal?</p><div class="ls-form-group"><label class="ls-form-label">Full Name</label><input type="text"class="ls-form-input"id="calc-name"placeholder="John Smith"></div><div class="ls-form-group"><label class="ls-form-label">Email</label><input type="email"class="ls-form-input"id="calc-email"placeholder="john@company.com"></div><div class="ls-form-group"><label class="ls-form-label">Phone</label><input type="tel"class="ls-form-input"id="calc-phone"placeholder="(555) 123-4567"></div><div class="ls-calc-nav"><button class="ls-btn ls-btn-outline-dark"onclick="calcNext(3)">\u2190 Back</button><button class="ls-btn ls-btn-primary-std"onclick="calcSubmit()">See My Savings \u2192</button></div></div></div><div id="ls-calc-results"style="display:none;"></div></div></section>`;}
window.calcNext=function(step){$$('.ls-calc-step').forEach(s=>s.classList.remove('active'));const target=$(`.ls-calc-step[data-step="${step}"]`);if(target)target.classList.add('active');$$('.ls-calc-progress-step').forEach(s=>{s.classList.toggle('active',parseInt(s.dataset.step)<=step);});};window.calcSubmit=function(){const sqft=parseFloat($('#calc-sqft')?.value)||50000;const fixtures=parseFloat($('#calc-fixtures')?.value)||Math.round(sqft/100);const hours=parseFloat($('#calc-hours')?.value)||12;const rate=parseFloat($('#calc-rate')?.value)||0.12;const name=$('#calc-name')?.value||'';const email=$('#calc-email')?.value||'';const phone=$('#calc-phone')?.value||'';const avgWattOld=80;const avgWattNew=24;const savingsPerFixture=(avgWattOld-avgWattNew)*hours*365/1000*rate;const annualSavings=Math.round(savingsPerFixture*fixtures);const rebateEstimate=Math.round(fixtures*35);const projectCost=Math.round(fixtures*220);const paybackMonths=Math.round((projectCost-rebateEstimate)/annualSavings*12);const fiveYearROI=Math.round((annualSavings*5-projectCost+rebateEstimate)/projectCost*100);const co2=Math.round(fixtures*(avgWattOld-avgWattNew)*hours*365/1000*0.92/2000);console.log('Calculator submission:',{name,email,phone,sqft,fixtures,hours,rate,annualSavings,rebateEstimate,paybackMonths});$('#ls-calc-form').style.display='none';const results=$('#ls-calc-results');results.style.display='block';results.innerHTML=`<div style="text-align:center;margin-bottom:48px;"><div style="font-size:48px;margin-bottom:16px;">\uD83C\uDF89</div><h2 class="ls-section-title">Your Estimated Savings</h2><p class="ls-section-subtitle"style="margin:8px auto 0;">Based on ${fixtures.toLocaleString()}fixtures across ${sqft.toLocaleString()}SF</p></div><div class="ls-results-grid"><div class="ls-result-card"><div class="ls-result-num"data-counter data-target="${annualSavings}"data-prefix="$"data-counter-id="res-savings">$0</div><div class="ls-result-label">Annual Savings</div></div><div class="ls-result-card"><div class="ls-result-num"data-counter data-target="${rebateEstimate}"data-prefix="$"data-counter-id="res-rebates">$0</div><div class="ls-result-label">Est.Rebates</div></div><div class="ls-result-card"><div class="ls-result-num"data-counter data-target="${paybackMonths}"data-suffix=" mo"data-counter-id="res-payback">0</div><div class="ls-result-label">Payback Period</div></div></div><div class="ls-grid-2"style="margin-bottom:48px;"><div class="ls-result-card"><div class="ls-result-num"data-counter data-target="${fiveYearROI}"data-suffix="%"data-counter-id="res-roi">0</div><div class="ls-result-label">5-Year ROI</div></div><div class="ls-result-card"><div class="ls-result-num"data-counter data-target="${co2}"data-suffix=" tons"data-counter-id="res-co2">0</div><div class="ls-result-label">Annual CO\u2082 Reduction</div></div></div><div style="text-align:center;"><button class="ls-btn ls-btn-primary-std"onclick="navigate('#/contact')"style="font-size:18px;padding:18px 40px;">Get Your Custom Proposal \u2192</button><p style="font-size:14px;color:var(--color-gray);margin-top:16px;">Results are estimates.Your custom proposal will include engineering-verified numbers.</p></div>`;animateCounters(results);};function renderAboutPage(){setMeta('About LED Solutions','Commercial LED retrofit specialists with 147+ projects, $12.4M+ in verified savings. Engineering-grade solutions for the Southeast US.');return`${pageHero('About LED Solutions','Engineering-grade lighting solutions. Verified results.',IMAGES.team)}<section class="ls-section"><div class="ls-container"><div class="ls-grid-40-60"><div class="ls-reveal-left"><img class="ls-lazy"data-src="${IMAGES.team}"alt="Our Team"style="border-radius:16px;width:100%;height:400px;object-fit:cover;"></div><div class="ls-reveal-right"><div class="ls-section-label">Our Story</div><h2 class="ls-section-title">Built on results,<br>not promises.</h2><p style="color:var(--color-gray);margin-bottom:16px;">LED Solutions was founded on a simple principle:commercial lighting upgrades should deliver measurable,verified results — not just vendor estimates.</p><p style="color:var(--color-gray);margin-bottom:16px;">We bring engineering rigor to every project.Our team designs,installs,and commissions LED retrofit and controls solutions for commercial and industrial facilities across the Southeast United States.</p><p style="color:var(--color-gray);">With 147+completed projects and $12.4M+in verified client savings,we\'ve built our reputation on doing exactly what we say we\'ll do — and proving it with measurement and verification.</p>
            </div>
          </div>
        </div>
      </section>
      <section class="ls-section light">
        <div class="ls-container">
          <div style="text-align:center;margin-bottom:64px;">
            <div class="ls-section-label ls-reveal">Why LED Solutions</div>
            <h2 class="ls-section-title ls-reveal" data-delay="100">What sets us apart.</h2>
          </div>
          <div class="ls-grid-3">
            ${[
              { title: 'Engineering-First', desc: 'Photometric analysis,not guesswork.Every project starts with real data and delivers verified results.' },
              { title: 'Turnkey Execution', desc: 'Design,procurement,installation,commissioning,rebate capture.One partner handles everything.' },
              { title: 'Verified Savings', desc: '30/60/90-day measurement and verification.We prove the savings are real — not just projected.' },
              { title: 'Rebate Maximization', desc: '$2.1M+captured.We know every program and deadline.You get every dollar available.' },
              { title: 'Minimal Disruption', desc: 'Phased rollouts,after-hours work,clean job sites.Your operations continue uninterrupted.' },
              { title: 'Long-Term Partnership', desc: 'Dedicated support,warranty management,and ongoing optimization.We\'re here after the install.'},].map((v,i)=>`<div class="ls-card ls-reveal"data-delay="${i*80}"style="cursor:default;"><div class="ls-card-body"style="padding:32px;"><h3 class="ls-card-title"style="margin-bottom:12px;">${v.title}</h3><p class="ls-card-text">${v.desc}</p></div></div>`).join('')}</div></div></section><section class="ls-section dark"><div class="ls-container"><div class="ls-stats-row"><div class="ls-reveal"><div class="ls-stat-num"data-counter data-target="147"data-suffix="+"data-counter-id="ab1">0</div><div class="ls-stat-label">Projects</div></div><div class="ls-reveal"data-delay="100"><div class="ls-stat-num"data-counter data-target="12.4"data-prefix="$"data-suffix="M"data-decimals="1"data-counter-id="ab2">$0</div><div class="ls-stat-label">Client Savings</div></div><div class="ls-reveal"data-delay="200"><div class="ls-stat-num"data-counter data-target="68"data-suffix="%"data-counter-id="ab3">0</div><div class="ls-stat-label">Avg Reduction</div></div><div class="ls-reveal"data-delay="300"><div class="ls-stat-num"data-counter data-target="2.1"data-prefix="$"data-suffix="M"data-decimals="1"data-counter-id="ab4">$0</div><div class="ls-stat-label">Rebates Captured</div></div></div></div></section>${ctaBand('Ready to work with a team that delivers?','Start With a Free Audit','#/calculator')}`;}
function renderContactPage(){setMeta('Contact Us','Get in touch with LED Solutions for a free energy audit. Serving the Southeast United States.');return`${pageHero('Contact Us','Let\'s talk about your lighting.',IMAGES.contact)}<section class="ls-section"><div class="ls-container"><div class="ls-grid-60-40"><div class="ls-reveal-left"><h2 style="font-size:32px;font-weight:800;margin-bottom:32px;letter-spacing:-0.02em;">Send us a message</h2><form id="ls-contact-form"onsubmit="return handleContactSubmit(event)"><div class="ls-grid-2"><div class="ls-form-group"><label class="ls-form-label">Full Name*</label><input type="text"class="ls-form-input"id="contact-name"required></div><div class="ls-form-group"><label class="ls-form-label">Company</label><input type="text"class="ls-form-input"id="contact-company"></div></div><div class="ls-grid-2"><div class="ls-form-group"><label class="ls-form-label">Email*</label><input type="email"class="ls-form-input"id="contact-email"required></div><div class="ls-form-group"><label class="ls-form-label">Phone</label><input type="tel"class="ls-form-input"id="contact-phone"></div></div><div class="ls-form-group"><label class="ls-form-label">Facility Type</label><select class="ls-form-select"id="contact-facility"><option value="">Select type...</option><option>Office Building</option><option>Warehouse/Distribution</option><option>Retail/Shopping Center</option><option>Healthcare</option><option>Education</option><option>Industrial</option><option>Other</option></select></div><div class="ls-form-group"><label class="ls-form-label">Message</label><textarea class="ls-form-textarea"id="contact-message"placeholder="Tell us about your project..."></textarea></div><button type="submit"class="ls-btn ls-btn-primary-std"style="width:100%;justify-content:center;">Send Message \u2192</button></form><div id="ls-contact-success"style="display:none;text-align:center;padding:48px 0;"><div style="font-size:48px;margin-bottom:16px;">&#10003;</div><h3 style="font-size:24px;font-weight:700;margin-bottom:8px;">Message Sent!</h3><p style="color:var(--color-gray);">We'll be in touch within one business day.</p>
              </div>
            </div>
            <div class="ls-reveal-right">
              <div style="background:var(--color-light);border-radius:16px;padding:40px;margin-bottom:32px;">
                <h3 style="font-size:20px;font-weight:700;margin-bottom:24px;">Get in Touch</h3>
                <div style="margin-bottom:20px;">
                  <div style="font-size:13px;font-weight:600;color:var(--color-gray);text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;">Email</div>
                  <a href="mailto:${CONFIG.email}" style="font-weight:600;color:var(--color-dark);">${CONFIG.email}</a>
                </div>
                <div style="margin-bottom:20px;">
                  <div style="font-size:13px;font-weight:600;color:var(--color-gray);text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;">Phone</div>
                  <span style="font-weight:600;">${CONFIG.phone}</span>
                </div>
                <div>
                  <div style="font-size:13px;font-weight:600;color:var(--color-gray);text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;">Service Area</div>
                  <span style="font-weight:600;">${CONFIG.area}</span>
                </div>
              </div>
              <div style="background:var(--color-dark);border-radius:16px;padding:40px;color:#fff;text-align:center;height:200px;display:flex;align-items:center;justify-content:center;flex-direction:column;">
                <div style="font-size:24px;margin-bottom:8px;">\uD83D\uDCCD</div>
                <div style="font-size:18px;font-weight:700;">Southeast United States</div>
                <div style="font-size:14px;color:rgba(255,255,255,0.5);margin-top:4px;">Serving FL, GA, AL, SC, NC, TN, MS</div>
              </div>
            </div>
          </div>
        </div>
      </section>
    `;
  }

  window.handleContactSubmit = function(e) {
    e.preventDefault();
    // TODO: HubSpot form submission endpoint
    const data = {
      name: $('#contact-name')?.value,
      company: $('#contact-company')?.value,
      email: $('#contact-email')?.value,
      phone: $('#contact-phone')?.value,
      facility: $('#contact-facility')?.value,
      message: $('#contact-message')?.value,
    };
    console.log('Contact form submission:', data);
    $('#ls-contact-form').style.display = 'none';
    $('#ls-contact-success').style.display = 'block';
    return false;
  };

  // ── Page: Industries ───────────────────────────────────────────────
  function renderIndustriesPage() {
    setMeta('Industries We Serve', 'LED Solutions serves commercial real estate,industrial,retail,healthcare,and education markets.');
    return `
      ${pageHero('Industries We Serve', 'Specialized solutions for every building type.', IMAGES.cre)}
      <section class="ls-section">
        <div class="ls-container">
          <div class="ls-grid-3" style="margin-bottom:32px;">
            ${INDUSTRIES.map((ind, i) => `
              <div class="ls-card ls-reveal" data-delay="${i*100}" style="cursor:default;">
                <div class="ls-card-img-wrap"><img class="ls-card-img ls-lazy" data-src="${ind.img}" alt="${ind.title}"></div>
                <div class="ls-card-body">
                  <div class="ls-card-stat">${ind.stat}</div>
                  <div class="ls-card-stat-label" style="margin-bottom:12px;">Energy Savings</div>
                  <h3 class="ls-card-title">${ind.title}</h3>
                  <p class="ls-card-text">${ind.desc}</p>
                </div>
              </div>
            `).join('')}
          </div>
        </div>
      </section>
      ${ctaBand('Find out what\'s possible for your industry.','Get a Free Assessment','#/calculator')}`;}
function renderPrivacyPage(){setMeta('Privacy Policy','LED Solutions privacy policy.');return`<section class="ls-section"style="padding-top:calc(var(--nav-height) + 60px);"><div class="ls-container"style="max-width:800px;"><div class="ls-legal"><h1 class="ls-section-title ls-reveal">Privacy Policy</h1><p class="ls-reveal"data-delay="100"style="color:var(--color-gray);">Last updated:${new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'})}</p><h2>Information We Collect</h2><p>We collect information you provide directly,including name,email,phone number,and company information when you fill out forms on our website,request an audit,or use our savings calculator.</p><h2>How We Use Your Information</h2><p>We use your information to respond to inquiries,provide energy audits and proposals,improve our services,and send relevant communications about LED solutions and energy savings opportunities.</p><h2>Information Sharing</h2><p>We do not sell,trade,or rent your personal information to third parties.We may share information with utility companies as part of rebate applications,with your explicit consent.</p><h2>Data Security</h2><p>We implement appropriate security measures to protect your personal information against unauthorized access,alteration,disclosure,or destruction.</p><h2>Contact Us</h2><p>For questions about this Privacy Policy,contact us at<a href="mailto:${CONFIG.email}"style="color:var(--color-primary);font-weight:600;">${CONFIG.email}</a>.</p></div></div></section>`;}
function renderTermsPage(){setMeta('Terms of Service','LED Solutions terms of service.');return`<section class="ls-section"style="padding-top:calc(var(--nav-height) + 60px);"><div class="ls-container"style="max-width:800px;"><div class="ls-legal"><h1 class="ls-section-title ls-reveal">Terms of Service</h1><p class="ls-reveal"data-delay="100"style="color:var(--color-gray);">Last updated:${new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'})}</p><h2>Acceptance of Terms</h2><p>By accessing and using the LED Solutions website,you accept and agree to be bound by these Terms of Service.</p><h2>Services</h2><p>LED Solutions provides commercial and industrial LED lighting retrofit,smart controls integration,and utility rebate management services.All project proposals include specific terms,timelines,and warranties.</p><h2>Savings Estimates</h2><p>Calculator results and preliminary estimates are approximations based on industry averages.Actual savings depend on facility-specific conditions.Custom proposals include engineering-verified projections.</p><h2>Intellectual Property</h2><p>All content on this website,including text,graphics,logos,and images,is the property of LED Solutions and protected by applicable intellectual property laws.</p><h2>Limitation of Liability</h2><p>LED Solutions provides this website on an"as is"basis.We make no warranties regarding the completeness or accuracy of website content.</p><h2>Contact</h2><p>Questions about these Terms should be directed to<a href="mailto:${CONFIG.email}"style="color:var(--color-primary);font-weight:600;">${CONFIG.email}</a>.</p></div></div></section>`;}
function getRoute(){const hash=window.location.hash||'#/';return hash;}
function renderPage(route){countersAnimated={};if(route.startsWith('#/case-study/')){const id=route.replace('#/case-study/','');return renderCaseStudyPage(id);}
switch(route){case'#/':case'':return renderHomepage();case'#/services':return renderServicesPage();case'#/retrofit':return renderRetrofitPage();case'#/controls':return renderControlsPage();case'#/rebates':return renderRebatesPage();case'#/case-studies':return renderCaseStudiesPage();case'#/calculator':return renderCalculatorPage();case'#/about':return renderAboutPage();case'#/contact':return renderContactPage();case'#/industries':return renderIndustriesPage();case'#/privacy':return renderPrivacyPage();case'#/terms':return renderTermsPage();default:return renderHomepage();}}
function routeTo(route){if(route===currentRoute)return;const app=$('#ls-app');app.classList.add('transitioning');setTimeout(()=>{app.innerHTML=renderPage(route)+renderFooter().outerHTML;app.classList.remove('transitioning');window.scrollTo(0,0);observe(app);animateCounters(app);lazyLoad(app);updateNavActive(route);initTestimonials(app);currentRoute=route;},300);}
function updateNavActive(route){$$('.ls-nav-link').forEach(link=>{link.classList.toggle('active',link.dataset.route===route);});const nav=$('#ls-nav');const isDarkHero=route==='#/'||route===''||!['#/calculator','#/privacy','#/terms'].includes(route);if(isDarkHero){nav.classList.add('dark-hero');}else{nav.classList.remove('dark-hero');nav.classList.add('scrolled');}}
function initTestimonials(root){const container=root.querySelector('#ls-testimonial-container');if(!container)return;function render(){const t=TESTIMONIALS[testimonialIdx];container.innerHTML=`<div class="ls-testimonial-card"><p class="ls-testimonial-quote">\u201C${t.quote}\u201D</p><div class="ls-testimonial-name">${t.name}</div><div class="ls-testimonial-role">${t.role},${t.company}</div><div class="ls-testimonial-dots">${TESTIMONIALS.map((_,i)=>`<div class="ls-testimonial-dot ${i === testimonialIdx ? 'active' : ''}"onclick="setTestimonial(${i})"></div>`).join('')}</div></div>`;}
render();setInterval(()=>{testimonialIdx=(testimonialIdx+1)%TESTIMONIALS.length;render();},6000);}
window.setTestimonial=function(i){testimonialIdx=i;initTestimonials(document);};function initScrollHandlers(){let ticking=false;window.addEventListener('scroll',()=>{if(!ticking){requestAnimationFrame(()=>{const scrollY=window.scrollY;const nav=$('#ls-nav');const progress=$('#ls-scroll-progress');const sticky=$('#ls-sticky-cta');if(scrollY>100){nav.classList.add('scrolled');}else if(currentRoute==='#/'||currentRoute===''){nav.classList.remove('scrolled');}
const docHeight=document.documentElement.scrollHeight-window.innerHeight;const scrollPercent=docHeight>0?(scrollY/docHeight)*100:0;if(progress)progress.style.width=scrollPercent+'%';if(sticky&&!stickyDismissed&&currentRoute!=='#/calculator'){const threshold=docHeight*0.3;sticky.classList.toggle('show',scrollY>threshold);}
ticking=false;});ticking=true;}});}
function init(){loadFont();injectCSS();initObserver();document.body.innerHTML='';document.body.style.margin='0';document.body.appendChild(renderScrollProgress());document.body.appendChild(renderNav());document.body.appendChild(renderMobileMenu());const app=el('div',{id:'ls-app'});document.body.appendChild(app);document.body.appendChild(renderStickyCTA());$$('.ls-nav-link, .ls-nav-cta',document.body).forEach(link=>{link.addEventListener('click',(e)=>{e.preventDefault();const route=link.dataset.route;if(route)navigate(route);});});const hamburger=$('.ls-hamburger');const mobileMenu=$('#ls-mobile-menu');if(hamburger){hamburger.addEventListener('click',()=>{mobileMenu.classList.toggle('open');});}
const stickyClose=$('#ls-sticky-cta .ls-sticky-close');if(stickyClose){stickyClose.addEventListener('click',()=>{stickyDismissed=true;$('#ls-sticky-cta').classList.remove('show');});}
const route=getRoute();currentRoute=route;app.innerHTML=renderPage(route)+renderFooter().outerHTML;observe(app);animateCounters(app);lazyLoad(app);updateNavActive(route);initTestimonials(app);window.addEventListener('hashchange',()=>{const newRoute=getRoute();routeTo(newRoute);if(mobileMenu)mobileMenu.classList.remove('open');});initScrollHandlers();}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();